import sys
import heapq

def main():
    import sys
    input = sys.stdin.read
    data = input().split()

    N = int(data[0])
    D = list(map(int, data[1:N+1]))
    L1, C1, K1 = map(int, data[N+1:N+4])
    L2, C2, K2 = map(int, data[N+4:N+7])

    # DP[i][k1][k2] = min cost to cover first i sections using k1 type-1 and k2 type-2 sensors
    # Initialize with large value
    INF = float('inf')
    dp = [[[INF] * (K2 + 1) for _ in range(K1 + 1)] for __ in range(N + 1)]
    dp[0][0][0] = 0

    for i in range(N):
        for k1 in range(K1 + 1):
            for k2 in range(K2 + 1):
                if dp[i][k1][k2] == INF:
                    continue
                # Try using only type-1 sensors
                for cnt1 in range(1, K1 + 1):
                    if k1 + cnt1 > K1:
                        break
                    if cnt1 * L1 >= D[i]:
                        dp[i+1][k1 + cnt1][k2] = min(dp[i+1][k1 + cnt1][k2], dp[i][k1][k2] + cnt1 * C1)
                # Try using only type-2 sensors
                for cnt2 in range(1, K2 + 1):
                    if k2 + cnt2 > K2:
                        break
                    if cnt2 * L2 >= D[i]:
                        dp[i+1][k1][k2 + cnt2] = min(dp[i+1][k1][k2 + cnt2], dp[i][k1][k2] + cnt2 * C2)
                # Try using both types
                for cnt1 in range(1, K1 + 1):
                    if k1 + cnt1 > K1:
                        break
                    for cnt2 in range(1, K2 + 1):
                        if k2 + cnt2 > K2:
                            break
                        if cnt1 * L1 + cnt2 * L2 >= D[i]:
                            dp[i+1][k1 + cnt1][k2 + cnt2] = min(dp[i+1][k1 + cnt1][k2 + cnt2], dp[i][k1][k2] + cnt1 * C1 + cnt2 * C2)

    # Find the minimum cost among all valid combinations
    result = INF
    for k1 in range(K1 + 1):
        for k2 in range(K2 + 1):
            result = min(result, dp[N][k1][k2])

    if result == INF:
        print(-1)
    else:
        print(result)

if __name__ == "__main__":
    main()
